/**
 * Curated upstream smoke fixtures used to prove contributor-facing behavior across runtimes.
 *
 * Sources:
 * - `mozilla/pdf.js` `test/pdfs/arial_unicode_en_cidfont.pdf`
 * - `mozilla/pdf.js` `test/pdfs/vertical.pdf`
 */
export const publicSmokeFixtures = {
  identityHCidFont: {
    id: "identity-h-cidfont",
    fileName: "identity-h-cidfont.pdf",
    expectedMarkers: ["This is an Arial Unicode PDF", "from OpenOffice."],
    bytesBase64:
      "",
  },
  identityVCidFont: {
    id: "identity-v-cidfont",
    fileName: "identity-v-cidfont.pdf",
    expectedMarkers: ["あいうえお", "日本語"],
    bytesBase64:
      "",
  },
  encryptedStandardText: {
    id: "encrypted-standard-text",
    fileName: "encrypted-standard-text.pdf",
    userPassword: "user",
    expectedText: "Encrypted Shell",
    bytesBase64:
      "",
  },
  encryptedStandardTextAes256: {
    id: "encrypted-standard-text-aes-256",
    fileName: "crazyones-encrypted-256.pdf",
    userPassword: "password",
    expectedMarkers: [
      "The Crazy Ones",
      "October 14, 1998",
      "Heres to the crazy ones.",
      "people who are crazy enough to think they can change the world",
    ],
    bytesBase64:
      "",
  },
};

export function decodeFixturePdfBytes(base64) {
  if (typeof Uint8Array.fromBase64 === "function") {
    return Uint8Array.fromBase64(base64);
  }

  return Uint8Array.from(globalThis.atob(base64), (character) => character.charCodeAt(0));
}
